const campaigns = $input.first().json;

// Calculate ROAS for each
const analyzed = campaigns.map(c => ({
  ...c,
  roas: c.revenue / c.spend,
  cpa: c.spend / c.conversions,
  trend: c.roas_7d > c.roas_30d ? 'improving' : 'declining'
}));

// Identify underperformers and overperformers
const underperformers = analyzed.filter(c => c.roas < 2.0);
const overperformers = analyzed.filter(c => c.roas > 4.0);

return { analyzed, underperformers, overperformers };

const { underperformers, overperformers } = $input.first().json;

// Proposed reallocation
let proposedShift = 0;
const actions = [];

underperformers.forEach(c => {
  const reduction = c.dailyBudget * 0.3; // Reduce 30%
  proposedShift += reduction;
  actions.push({ campaign: c.id, action: 'reduce', amount: reduction });
});

overperformers.forEach(c => {
  const increase = c.dailyBudget * 0.2; // Increase 20%
  if (proposedShift > 0) {
    proposedShift -= increase;
    actions.push({ campaign: c.id, action: 'increase', amount: increase });
  }
});

return { proposedShift: Math.abs(proposedShift), actions, needsApproval: Math.abs(proposedShift) > 5000 };

